#!/usr/bin/env bash
# 0.sh — 新账号起号（0 粉到稳定出单） SOP walkthrough for 抖音直播带货 (商家 / 主播 / 直播间运营 + 千川 / 巨量引擎广告投放 + 选品 + 流量场承接 + 合规).
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="抖音直播带货 (商家 / 主播 / 直播间运营 + 千川 / 巨量引擎广告投放 + 选品 + 流量场承接 + 合规)"
WORKFLOW="新账号起号（0 粉到稳定出单）"

usage() {
  cat <<EOF
0.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./0.sh             # interactive
  ./0.sh --dry-run
  ./0.sh --json
  ./0.sh --explain
  ./0.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "新账号起号（0 粉到稳定出单）" 工作流。

一句话: 从「新开一个直播间、0 粉无标签」到「跑通『流量-转化』正循环、能稳定出单」的冷启动工作流 —— 是 workflow 2「0→1 阶段」的更细粒度展开，也是行业黑话「起号」对应的标准动作。

入门 SOP 共 5 步, 失败模式自检 4 项。

相关心智模型:
  • 算法生意：直播间是做给算法看的，不是做给用户看的: 抖音直播带货的本质是「向推荐算法证明这个直播间值得被推流」——理解算法如何用停留 / 转化 / GPM 这组指标分配免费流量，比话术技巧更底层；流量是非线性「大爆发」的，核心变量是流量 × 选品。
  • 承接 > 引流：流量是放大器不是发动机: 直播间能不能做起来，发动机是「承接能力」(UV 价值 / 停留时长 / GPM / 品组 / 话术)，流量 (自然 + 投流) 只是把这台发动机的输出放大——承接是负数时，加流量等于加速亏钱。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**账号基建（前 3 天）**: 实名认证（身份证+人脸）；设备正常使用 3 天以上避免被判营销号；账号头像/昵称/简介体现赛道定位。**跳过会发生什么**：未实名无开播权限；新设备秒开播易被判营销号限流。 evidence: [T03-S006]"
  "**养标签（前 3 天，与上并行）**: 每天 30 分钟+看同类目直播，做点赞/评论/停留互动，让系统给账号打精准标签。**跳过会发生什么**：标签不准，开播后流量推给不对的人，转化差。 evidence: [T03-S006]"
  "**选起号路径**: 三选一 —— 短视频起号（靠优质短视频拿自然推荐导流）、千川单品起号（一个爆品+优质素材跑千川）、螺旋起号（让各项数据按 7 天螺旋上升骗系统给更高流量池）。**跳过会发生什么**：没有明确起号路径则动作散、数据不成体系。 evidence: [T03-S006]（Wave 1 Track 06 seed）"
  "**跑数据过测试**: 新直播间要过平台多次（约 3 次）流量测试，重点把停留时长（权重占比约 40%，目标人均≥2 分钟）和进场留存做达标。**跳过会发生什么**：测试不达标则流量池晋级失败、掉级，起号失败。 evidence: [T03-S006]"
  "**稳定开播 + 切片复用**: 每周稳定开播 3 场以上；把直播切成短视频二次分发引流。**跳过会发生什么**：开播不稳定算法不给积累权重；不切片则一次直播内容浪费。 evidence: [T03-S006]"
)
declare -a FAILURE_MODES=(
  "**「先涨粉再带货」**: 触发原因 —— 把直播间当短视频账号运营。后果 —— 白白等涨粉，错过起号窗口（直播和短视频是两套算法，涨粉≠能卖货）。怎么避免：**0 粉就开播带货，把「跑通流量-转化模型」当目标，涨粉只是副产物**。 evidence: [T03-S006]"
  "**新设备秒开播被判营销号**: 触发原因 —— 不知道有养号期。后果 —— 账号被限流，起号还没开始就废。怎么避免：**新设备正常使用 3 天以上、账号资料填完整再开播**。 evidence: [T03-S006]"
  "**靠螺旋起号刷数据骗流量池**: 触发原因 —— 想走捷径。后果 —— 2026 新规下数据真实性违规、黑名单封堵换号，号废了也救不回。怎么避免：**用真实承接（停留/转化）跑数据，不靠刷量；账号数据做烂比开新号还难救**。 evidence: [T03-S006, T03-S011]"
  "**CLI 化暗示 (v0.6+)**: 可抽进 \`cli/workflow/account-bootstrap.sh\`（如「你的直播间停留时长到人均 2 分钟了吗？」「你是 0 粉就开播了还是在等涨粉？」）。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "0-walkthrough"
fi
